UPDATE patients
SET
    risk_score = #{riskScore},
    risk_level = #{riskLevel},
    ai_suggestion = #{aiSuggestion}
WHERE patient_name = #{patientName}

mapper.select:
SELECT M.microbe_name_standard AS microbe_name, AVG(M.abundance_value) AS avg_abundance, STDDEV_POP(M.abundance_value) AS std_abundance, COUNT(DISTINCT CONCAT(M.patient_id, ':', M.sample_id)) AS sample_hits FROM patients P JOIN microbe_abundance_standard M ON P.patient_id = M.patient_id WHERE LOWER(TRIM(P.disease)) = 'healthy'
AND P.body_site = #{bodySite}
AND M.microbe_name_standard IN
#{name}
GROUP BY M.microbe_name_standard ORDER BY avg_abundance DESC, sample_hits DESC

SELECT M.microbe_name_standard AS microbe_name, AVG(M.abundance_value) AS avg_abundance, STDDEV_POP(M.abundance_value) AS std_abundance, COUNT(DISTINCT CONCAT(M.patient_id, ':', M.sample_id)) AS sample_hits FROM patients P JOIN microbe_abundance_standard M ON P.patient_id = M.patient_id WHERE LOWER(TRIM(P.disease)) = 'healthy'
AND P.body_site = #{bodySite}
GROUP BY M.microbe_name_standard ORDER BY avg_abundance DESC, sample_hits DESC

SELECT CONCAT(M.patient_id, ':', M.sample_id) AS sample_key, M.patient_id AS patient_id, M.sample_id AS sample_id, M.microbe_name_standard AS microbe_name, M.abundance_value AS abundance_value FROM patients P JOIN microbe_abundance_standard M ON P.patient_id = M.patient_id WHERE LOWER(TRIM(P.disease)) = 'healthy'
AND P.body_site = #{bodySite}
AND M.microbe_name_standard IN
#{name}
ORDER BY sample_key ASC, M.microbe_name_standard ASC

SELECT M.microbe_name_standard AS microbe_name, AVG(M.abundance_value) AS avg_abundance, COUNT(DISTINCT CONCAT(M.patient_id, ':', M.sample_id)) AS sample_hits FROM patients P JOIN microbe_abundance_standard M ON P.patient_id = M.patient_id WHERE LOWER(TRIM(P.disease)) = 'healthy'
AND P.body_site = #{bodySite}
GROUP BY M.microbe_name_standard ORDER BY avg_abundance DESC, sample_hits DESC LIMIT #{limit}
